235	// RunWithConfig is the SD-024 successor to Run. It accepts a sealed
236	// ResolvedConfig (durable knobs) and an AgentRunRuntime (plumbing +
237	// per-invocation intent), assembles an equivalent RunOptions, and
238	// delegates to Run. Behavior is identical to Run with an
239	// equivalently-populated RunOptions.
240	//
241	// Stage 2 of SD-024: this method exists alongside Run; production
242	// callers have not migrated yet.
243	func (r *Runner) RunWithConfig(ctx context.Context, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
244		sessionLogDir := runtime.SessionLogDirOverride
245		if sessionLogDir == "" {
246			sessionLogDir = rcfg.SessionLogDir()
247		}
248		opts := RunOptions{
249			Context:       ctx,
250			Harness:       rcfg.Harness(),
251			Prompt:        runtime.Prompt,
252			PromptFile:    runtime.PromptFile,
253			PromptSource:  runtime.PromptSource,
254			Correlation:   runtime.Correlation,
255			Model:         rcfg.Model(),
256			Provider:      rcfg.Provider(),
257			ModelRef:      rcfg.ModelRef(),
258			Effort:        rcfg.Effort(),
259			Timeout:       rcfg.Timeout(),
260			WallClock:     rcfg.WallClock(),
261			WorkDir:       runtime.WorkDir,
262			Permissions:   rcfg.Permissions(),
263			SessionLogDir: sessionLogDir,
264		}
265		return r.Run(opts)
266	}
