344	// resolveHarness looks up the harness by name and checks availability.
345	func (r *Runner) resolveHarness(opts RunOptions) (harnessConfig, string, error) {
346		name := opts.Harness
347		if name == "" {
348			// --provider names a harness directly (e.g. "agent", "local") →
349			// treat it as a harness override so the routing engine never
350			// falls through to a different harness.
351			if opts.Provider != "" {
352				resolved := resolveHarnessAlias(opts.Provider)
353				if r.registry.Has(resolved) {
354					name = resolved
355				}
356			}
357		}
358		if name == "" {
359			name = r.Config.Harness
360		}
361		harness, ok := r.registry.Get(name)
362		if !ok {
363			return harnessConfig{}, "", fmt.Errorf("agent: unknown harness: %s", name)
364		}
365		// Embedded and HTTP-only harnesses don't need a binary in PATH.
366		if name != "virtual" && name != "agent" && name != "script" && !harness.IsHTTPProvider {
367			if _, err := r.LookPath(harness.Binary); err != nil {
368				return harnessConfig{}, "", fmt.Errorf("agent: harness %s not available: %s not found in PATH", name, harness.Binary)
369			}
370		}
371		return harness, name, nil
372	}
