374	// resolvePrompt reads the prompt from text or file.
375	func (r *Runner) resolvePrompt(opts RunOptions) (string, error) {
376		prompt := opts.Prompt
377		if opts.PromptFile != "" {
378			data, err := readPromptFileBounded(opts.PromptFile)
379			if err != nil {
380				return "", fmt.Errorf("agent: read prompt file: %w", err)
381			}
382			prompt = string(data)
383		}
384		if prompt == "" {
385			return "", fmt.Errorf("agent: prompt is required")
386		}
387		return prompt, nil
388	}
