390	// resolveModel picks the model from opts, per-harness config, or global config.
391	func (r *Runner) resolveModel(opts RunOptions, harnessName string) string {
392		if opts.Model != "" {
393			return opts.Model
394		}
395		if m, ok := r.Config.Models[harnessName]; ok {
396			return m
397		}
398		if r.Config.Model != "" {
399			return r.Config.Model
400		}
401		return ""
402	}
