404	func (r *Runner) resolveReasoningLevels(harnessName string, harness harnessConfig) []string {
405		if r.Config.ReasoningLevels != nil {
406			if levels, ok := r.Config.ReasoningLevels[harnessName]; ok && len(levels) > 0 {
407				return append([]string{}, levels...)
408			}
409		}
410		if len(harness.ReasoningLevels) > 0 {
411			return append([]string{}, harness.ReasoningLevels...)
412		}
413		return []string{}
