534	// UsageData holds structured token usage from a structured agent output.
535	type UsageData struct {
536		InputTokens  int
537		OutputTokens int
538		CostUSD      float64
539	}
540	
541	// ExtractUsage parses structured token usage from agent output.
542	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
543	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
544	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
545	func ExtractUsage(harnessName string, output string) UsageData {
546		switch harnessName {
547		case "codex":
548			for _, line := range strings.Split(output, "\n") {
549				line = strings.TrimSpace(line)
550				if line == "" || !strings.Contains(line, `"turn.completed"`) {
551					continue
552				}
553				var event struct {
554					Type  string `json:"type"`
555					Usage struct {
556						InputTokens  int `json:"input_tokens"`
557						OutputTokens int `json:"output_tokens"`
558					} `json:"usage"`
559				}
560				if err := json.Unmarshal([]byte(line), &event); err != nil {
561					continue
562				}
563				if event.Type == "turn.completed" {
564					return UsageData{
565						InputTokens:  event.Usage.InputTokens,
566						OutputTokens: event.Usage.OutputTokens,
567					}
568				}
569			}
570			return UsageData{}
571		case "claude":
572			// Claude may emit either the legacy single-JSON envelope
573			// ({"usage":{...},"total_cost_usd":N,"result":"..."}) or a stream-json
574			// sequence of one JSON event per line, the last of which is a
575			// {"type":"result",...} event with the same usage/cost fields.
576			return extractUsageClaude(output)
577		case "opencode":
578			// opencode -f json emits a JSON object; parse usage fields if present.
579			var envelope struct {
580				Usage struct {
581					InputTokens  int `json:"input_tokens"`
582					OutputTokens int `json:"output_tokens"`
583				} `json:"usage"`
584				TotalCostUSD float64 `json:"total_cost_usd"`
585			}
586			if err := json.Unmarshal([]byte(output), &envelope); err != nil {
587				// Try last non-empty line (in case of preamble).
588				lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
589				last := ""
590				for i := len(lines) - 1; i >= 0; i-- {
591					if strings.TrimSpace(lines[i]) != "" {
592						last = lines[i]
593						break
594					}
595				}
596				if last == "" {
597					return UsageData{}
598				}
599				if err2 := json.Unmarshal([]byte(last), &envelope); err2 != nil {
600					return UsageData{}
601				}
602			}
603			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
604				return UsageData{}
605			}
606			return UsageData{
607				InputTokens:  envelope.Usage.InputTokens,
608				OutputTokens: envelope.Usage.OutputTokens,
609				CostUSD:      envelope.TotalCostUSD,
610			}
611		case "pi":
612			// pi outputs JSONL - cost is in intermediate events, summary at end has no cost
613			// Scan backwards to find the last line with cost data
614			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
615			var inputTokens, outputTokens int
616			var costUSD float64
617			for i := len(lines) - 1; i >= 0; i-- {
618				line := strings.TrimSpace(lines[i])
619				if line == "" {
620					continue
621				}
622				// Try to parse as pi event with usage/cost
623				// Format: {"type":"text_end","message":{"usage":{"input":N,"output":M,"cost":{"total":X}}}}
624				var event struct {
625					Type    string `json:"type"`
626					Message struct {
627						Usage struct {
628							Input  int `json:"input"`
629							Output int `json:"output"`
630							Cost   struct {
631								Total float64 `json:"total"`
632							} `json:"cost"`
633						} `json:"usage"`
634					} `json:"message"`
635					Partial struct {
636						Usage struct {
637							Input  int `json:"input"`
638							Output int `json:"output"`
639							Cost   struct {
640								Total float64 `json:"total"`
641							} `json:"cost"`
642						} `json:"usage"`
643					} `json:"partial"`
644				}
645				if err := json.Unmarshal([]byte(line), &event); err != nil {
646					continue
647				}
648				// Check message.usage first, then partial.usage
649				if event.Message.Usage.Input > 0 || event.Message.Usage.Output > 0 {
650					inputTokens = event.Message.Usage.Input
651					outputTokens = event.Message.Usage.Output
652					costUSD = event.Message.Usage.Cost.Total
653					break
654				}
655				if event.Partial.Usage.Input > 0 || event.Partial.Usage.Output > 0 {
656					inputTokens = event.Partial.Usage.Input
657					outputTokens = event.Partial.Usage.Output
658					costUSD = event.Partial.Usage.Cost.Total
659					break
660				}
661			}
662			return UsageData{
663				InputTokens:  inputTokens,
664				OutputTokens: outputTokens,
665				CostUSD:      costUSD,
666			}
667		case "gemini":
668			// gemini outputs single JSON with stats.models[].tokens (no cost in JSON)
669			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
670			last := ""
671			for i := len(lines) - 1; i >= 0; i-- {
672				if strings.TrimSpace(lines[i]) != "" {
673					last = lines[i]
674					break
675				}
676			}
677			if last == "" {
678				return UsageData{}
679			}
680			var envelope struct {
681				Stats struct {
682					Models map[string]struct {
683						Tokens struct {
684							Input int `json:"input"`
685							Total int `json:"total"`
686						} `json:"tokens"`
687					} `json:"models"`
688				} `json:"stats"`
689			}
690			if err := json.Unmarshal([]byte(last), &envelope); err != nil {
691				return UsageData{}
692			}
693			inputTokens := 0
694			outputTokens := 0
695			for _, model := range envelope.Stats.Models {
696				inputTokens += model.Tokens.Input
697				outputTokens += model.Tokens.Total - model.Tokens.Input
698			}
699			// Gemini JSON output doesn't include cost
700			return UsageData{
701				InputTokens:  inputTokens,
702				OutputTokens: outputTokens,
703				CostUSD:      0,
704			}
705		default:
706			return UsageData{}
707		}
708	}
709	
710	// ExtractOutput extracts clean text from raw agent output based on harness format.
711	// For codex: scans JSONL for type=item.completed with item.type=agent_message, returns item.text
712	// For claude: parses JSON envelope and returns the 'result' field
713	// For agent/opencode: returns output as-is (no transformation needed)
714	// For unknown harnesses or malformed input: returns output as-is
715	func ExtractOutput(harnessName string, rawOutput string) string {
716		switch harnessName {
717		case "codex":
718			return extractOutputCodex(rawOutput)
719		case "claude":
720			return extractOutputClaude(rawOutput)
721		case "agent", "opencode":
722			// agent and opencode return clean text directly
723			return rawOutput
724		case "pi", "gemini":
725			return extractOutputPiGemini(rawOutput)
726		default:
727			// Unknown harnesses return output as-is
728			return rawOutput
729		}
730	}
731	
732	func extractOutputPiGemini(rawOutput string) string {
733		// pi outputs JSONL (last line has summary), gemini outputs single JSON
734		// Try to parse the last non-empty line for the response field
735		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
736		last := ""
737		for i := len(lines) - 1; i >= 0; i-- {
738			if strings.TrimSpace(lines[i]) != "" {
739				last = lines[i]
740				break
741			}
742		}
743		if last == "" {
744			return rawOutput
745		}
746		var envelope struct {
747			Response string `json:"response"`
748		}
749		if err := json.Unmarshal([]byte(last), &envelope); err != nil {
750			return rawOutput
751		}
752		return envelope.Response
753	}
754	
755	func extractOutputCodex(rawOutput string) string {
756		for _, line := range strings.Split(rawOutput, "\n") {
757			line = strings.TrimSpace(line)
758			if line == "" {
759				continue
760			}
761			var item struct {
762				Type string `json:"type"`
763				Item struct {
764					Type string `json:"type"`
765					Text string `json:"text"`
766				} `json:"item"`
767			}
768			if err := json.Unmarshal([]byte(line), &item); err != nil {
769				continue
770			}
771			if item.Type == "output" && item.Item.Type == "agent_message" {
772				return item.Item.Text
773			}
774		}
775		return rawOutput
776	}
777	
778	func extractOutputClaude(rawOutput string) string {
779		// Legacy non-streaming mode: single JSON envelope with a "result" field.
780		var envelope struct {
781			Result string `json:"result"`
782		}
783		if err := json.Unmarshal([]byte(rawOutput), &envelope); err == nil && envelope.Result != "" {
784			return envelope.Result
785		}
786		// Stream-json mode: scan lines for the final {"type":"result",...} event.
787		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
788		for i := len(lines) - 1; i >= 0; i-- {
789			line := strings.TrimSpace(lines[i])
790			if line == "" {
791				continue
792			}
793			var ev struct {
794				Type   string `json:"type"`
795				Result string `json:"result"`
796			}
797			if err := json.Unmarshal([]byte(line), &ev); err == nil {
798				if ev.Type == "result" && ev.Result != "" {
799					return ev.Result
800				}
801				if ev.Type == "" && ev.Result != "" {
802					// Legacy envelope as last line.
803					return ev.Result
804				}
805			}
806		}
807		return rawOutput
808	}
809	
810	// extractUsageClaude parses token usage and cost from claude output.
811	// It handles both the legacy non-streaming envelope and the stream-json
812	// format (one JSON event per line, final "result" event carries usage).
813	func extractUsageClaude(output string) UsageData {
814		parse := func(s string) (UsageData, bool) {
815			var envelope struct {
816				Type  string `json:"type"`
817				Usage struct {
818					InputTokens  int `json:"input_tokens"`
819					OutputTokens int `json:"output_tokens"`
820				} `json:"usage"`
821				TotalCostUSD float64 `json:"total_cost_usd"`
822			}
823			if err := json.Unmarshal([]byte(s), &envelope); err != nil {
824				return UsageData{}, false
825			}
826			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
827				return UsageData{}, false
828			}
829			return UsageData{
830				InputTokens:  envelope.Usage.InputTokens,
831				OutputTokens: envelope.Usage.OutputTokens,
832				CostUSD:      envelope.TotalCostUSD,
833			}, true
834		}
835	
836		// Try whole output as a single JSON envelope first (legacy path).
837		if u, ok := parse(output); ok {
838			return u
839		}
840		// Stream-json: scan lines, prefer the final "type":"result" event,
841		// else fall back to the last line that parses with usage.
842		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
843		for i := len(lines) - 1; i >= 0; i-- {
844			line := strings.TrimSpace(lines[i])
845			if line == "" {
846				continue
847			}
848			if u, ok := parse(line); ok {
849				return u
850			}
851		}
852		return UsageData{}
853	}
854	
855	// ExtractTokens parses token usage from agent output using the harness's pattern.
856	// For codex, it delegates to ExtractUsage and returns total tokens (input + output).
857	func ExtractTokens(output string, harness harnessConfig) int {
858		if harness.Name == "codex" {
859			usage := ExtractUsage("codex", output)
860			if usage.InputTokens > 0 || usage.OutputTokens > 0 {
861				return usage.InputTokens + usage.OutputTokens
862			}
863		}
864		if harness.TokenPattern == "" {
865			return 0
866		}
867		re, err := regexp.Compile(harness.TokenPattern)
868		if err != nil {
869			return 0
870		}
871		matches := re.FindStringSubmatch(output)
872		if len(matches) > 1 {
873			cleaned := strings.ReplaceAll(matches[1], ",", "")
874			n, _ := strconv.Atoi(cleaned)
875			return n
876		}
877		return 0
878	}
