523	// CondenseOutput filters raw agent output to keep only progress-relevant lines.
524	// The canonical implementation lives in agent/internal/comparison.CondenseOutput.
525	func CondenseOutput(input, namespacePrefix string) string {
526		var kept []string
527		skippingTokens := false
528		skippingDiff := false
529		blankRun := 0
530		lastWasKept := false
531		keepNextResult := false
532	
533		lines := strings.Split(input, "\n")
534		if len(lines) > 0 && lines[len(lines)-1] == "" {
535			lines = lines[:len(lines)-1]
536		}
537	
538		for _, line := range lines {
539			if strings.HasPrefix(line, "Commands run:") {
540				continue
541			}
542			if line == "tokens used" {
543				skippingTokens = true
544				continue
545			}
546			if skippingTokens {
547				skippingTokens = false
548				continue
549			}
550			if condenseIsDiffHeader(line) {
551				skippingDiff = true
552				continue
553			}
554			if skippingDiff {
555				if condenseIsDiffHeader(line) {
556					continue
557				}
558				if len(line) > 0 && (line[0] == '+' || line[0] == '-' || line[0] == ' ') {
559					continue
560				}
561				skippingDiff = false
562			}
563			if line == "" {
564				blankRun++
565				continue
566			}
567			keep := false
568			if keepNextResult {
569				keep = true
570				keepNextResult = false
571			}
572			if namespacePrefix != "" && strings.HasPrefix(line, namespacePrefix) {
573				keep = true
574			}
575			if strings.HasPrefix(line, "$ ") {
576				keep = true
577				keepNextResult = true
578			}
579			for _, kw := range []string{"error", "Error", "ERROR", "warning", "Warning", "WARN", "FAIL", "fail", "panic"} {
580				if strings.Contains(line, kw) {
581					keep = true
582					break
583				}
584			}
585			for _, kw := range []string{"hx-", "helix-", "FEAT-", "US-", "COMPLETE", "BLOCKED", "CLOSED", "closed", "commit "} {
586				if strings.Contains(line, kw) {
587					keep = true
588					break
589				}
590			}
591			if len(line) > 0 && condenseIsAlphaNumUnderscore(rune(line[0])) && strings.Contains(line, ":") {
592				keep = true
593			}
594			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "|") || strings.HasPrefix(line, " |") || strings.HasPrefix(line, "**") {
595				keep = true
596			}
597			if strings.HasPrefix(line, "Phase") || strings.HasPrefix(line, "Step") || strings.HasPrefix(line, "---") {
598				keep = true
599			}
600			if keep {
601				if lastWasKept && blankRun > 0 {
602					kept = append(kept, "")
603				}
604				blankRun = 0
605				lastWasKept = true
606				kept = append(kept, line)
607			}
608		}
609	
610		if len(kept) == 0 {
611			return ""
612		}
613		result := strings.Join(kept, "\n")
614		return condenseTrimBlankLines(result)
615	}
616	
617	func condenseIsDiffHeader(line string) bool {
618		return strings.HasPrefix(line, "diff --git ") ||
619			strings.HasPrefix(line, "index ") ||
620			strings.HasPrefix(line, "--- a/") ||
621			strings.HasPrefix(line, "+++ b/") ||
622			strings.HasPrefix(line, "@@ ")
623	}
624	
625	func condenseIsAlphaNumUnderscore(r rune) bool {
626		return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_'
627	}
628	
629	func condenseTrimBlankLines(s string) string {
630		lines := strings.Split(s, "\n")
631		start := 0
632		for start < len(lines) && strings.TrimSpace(lines[start]) == "" {
633			start++
634		}
635		end := len(lines)
636		for end > start && strings.TrimSpace(lines[end-1]) == "" {
637			end--
638		}
639		return strings.Join(lines[start:end], "\n")
640	}
